@functools.cached_property
def _variant_lookup(self) -> dict[str, "ProductVariant"]:
    """
    Build once per process lifetime. O(1) lookup.
    Catalog is immutable (in-code) — safe to cache forever.
    When catalog moves to DB, invalidate this on reload.
    """
    lookup: dict[str, "ProductVariant"] = {}
    for product_id in VARIANTS:
        for v in self._list_variants_raw(product_id):
            lookup[v.variant_id] = v
    return lookup

def get_variant(self, variant_id: str) -> "ProductVariant":
    v = self._variant_lookup.get(variant_id)
    if v is None:
        raise KeyError(f"Variant not found: {variant_id!r}")
    return v

