import time
from app.services.product_service import product_service


def test_get_variant_o1_lookup():
    """get_variant must not do linear scan."""
    start = time.monotonic()
    for _ in range(5_000):
        try:
            product_service.get_variant("hex-bolt-iso4014-m8x30")
        except KeyError:
            pass
    elapsed = time.monotonic() - start
    assert elapsed < 0.5, f"get_variant too slow for 5000 calls: {elapsed:.3f}s"


def test_alembic_migration_0002_tables():
    """geometry_cache_metrics table must exist after migrations."""
    from sqlalchemy import inspect
    from app.core.database import engine
    inspector = inspect(engine)
    # Only validates when using postgres (not sqlite)
    if "postgresql" in str(engine.url):
        assert "geometry_cache_metrics" in inspector.get_table_names()

