"""Prometheus text-format metrics endpoint.""" from fastapi import APIRouter, Request from fastapi.responses import PlainTextResponse
router = APIRouter(tags=["observability"])
_METRIC_HELP = { "cad_platform_requests_total": ("Total HTTP requests handled", "counter"), "cad_platform_request_latency_ms_total": ("Cumulative request latency in milliseconds", "counter"), "cad_platform_jobs_queued_total": ("Total generation jobs queued to Celery", "counter"), "cad_platform_jobs_completed_total": ("Total generation jobs completed successfully", "counter"), "cad_platform_jobs_failed_total": ("Total generation jobs that failed", "counter"), "cad_platform_cache_hits_total": ("Total model resolver cache hits", "counter"), "cad_platform_cache_misses_total": ("Total model resolver cache misses", "counter"), "cad_platform_generate_inline_total": ("Total inline (synchronous) generations", "counter"), "cad_platform_generate_inline_ms_total": ("Cumulative inline generation time in milliseconds", "counter"), }
@router.get("/metrics", response_class=PlainTextResponse, summary="Prometheus metrics", description="Prometheus text format. Restrict access to internal network in production.") def prometheus_metrics(request: Request) -> str: m: dict = request.app.state.metrics lines: list[str] = [] for metric_name, (help_text, metric_type) in _METRIC_HELP.items(): value = m.get(metric_name, 0) lines.append(f"# HELP {metric_name} {help_text}") lines.append(f"# TYPE {metric_name} {metric_type}") lines.append(f"{metric_name} {value}") lines.append("") return "\n".join(lines)
